public class Person
{
    private static DateTime dateOfBirth;
    private static int expectedFingers;

    public Person(DateTime birthday)
    {
        dateOfBirth = birthday;  // Noncompliant - now everyone has this birthday
        expectedFingers = 10;    // Noncompliant - static field updated in constructor
    }
}

compliant:
public class Person
{
    private DateTime dateOfBirth;              // Instance field
    private static int expectedFingers = 10;   // Static field initialized inline

    public Person(DateTime birthday)
    {
        this.dateOfBirth = birthday;  // Compliant - instance field
    }
}
